import React from 'react';
import { Link } from 'react-router-dom';
import "./Yazan.css";

const Navbar = () => {
  const [scrolled, setScrolled] = React.useState(false);

  React.useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <nav className={`navbar ${scrolled ? "scrolled" : ""}`}>
      <div className="navbar-container">
        <div className="navbar-logo">
          <span className="logo-icon">🎓</span>
          <span className="logo-text">مستشارك الأكاديمي الذكي</span>
        </div>
        <div className="navbar-links">
          <a href="!" className="nav-link">تحميل دخول</a>
          <Link to="/login" className="nav-link">تسجل دخول</Link>
          <button className="btn-primary">ابدأ الاختبار</button>
          <span className="hamburger">☰</span>
        </div>
      </div>
    </nav>
  );
};

const YazanHomePage = () => {
  return (
    <div className="app" dir="rtl">
      <Navbar />
      {/* Rest of original content - Hero, HowItWorks, etc. Add your full JSX here */}
      <div>Full HomePage content...</div>
    </div>
  );
};

export default YazanHomePage;
